import requests

def lookup_order(order_id: str):
    response = requests.get(f"https://crm.example.com/orders/{order_id}", headers={"Authorization": "Bearer token"})
    return response.json()

support_specialist.register_for_llm(
    name="lookup_order",
    description="Get order details by ID",
)(lookup_order)

def create_ticket(customer_id: str, issue_summary: str, priority: str = "medium"):
    ticket_data = {
        "customer_id": customer_id,
        "summary": issue_summary,
        "priority": priority,
        "agent_notes": "Auto-generated from AG2 conversation"
    }
    requests.post("https://crm.example.com/tickets", json=ticket_data)
    return "Ticket created successfully"

support_specialist.register_for_llm(name="create_ticket", description="Create support ticket")(create_ticket)

