from vex_sdk import VexClient

vex = VexClient(api_key="vex-your-key")

def vex_message_hook(message, sender, recipient):
    result = vex.verify({
        "text": message.content,
        "verifications": ["response_accuracy", "pii_filtering", "tone_consistency"],
        "context": {"domain": "customer_support"}
    })
    if not result.approved:
        return "[VEX BLOCKED: " + result.reason + "]"
    return message

manager.message_hooks.append(vex_message_hook)

vex_policy = {
    "name": "customer_pii_policy",
    "verifications": {
        "pii_filtering": {
            "enabled": True,
            "patterns": ["SSN", "credit_card", "email", "phone"],
            "action": "block"
        }
    },
    "risk_profile": "high"
}
vex.create_policy(vex_policy)

# Apply to group chat
manager.register_policy("customer_pii_policy")

def tone_escalation_hook(message):
    checks = vex.verify({
        "text": message.content,
        "verifications": [
            "tone_consistency:positive|empathetic",
            "policy_compliance",
            "escalation_triggers:refund|legal|abuse"
        ]
    })

    if checks.escalation_detected:
        manager.select_speaker("escalation_agent")

    if not checks.approved:
        raise ValueError(f"Verification failed: {checks.reason}")
    return message

groupchat.register_message_hook(tone_escalation_hook)
